import type { TreeNode } from '../../types'
import type { GeneratorContext } from '../nodeExpressionGenerator.types'

function resolveConditionDataType(node: TreeNode, context: GeneratorContext): string {
  const nodeDataTypes = context.parameterDataTypes.get(node.id)
  return nodeDataTypes?.get('condition_value') || 'string'
}

export function getFieldConditionDataType(node: TreeNode, context: GeneratorContext): string {
  return resolveConditionDataType(node, context)
}
