import type { FunctionParameter, NodeValue } from '../../types'
import type { ValidationError } from './types'
import { hasComparableValue, hasParameterValue, requiresComparisonValue } from './shared'

interface FunctionValidationNode {
  id: string
  functionName?: string
  parameters?: FunctionParameter[]
  comparison?: string
  value?: NodeValue
}

interface ValidateFunctionNodeOptions {
  requireFunctionName?: boolean
}

export function validateFunctionNode(
  node: FunctionValidationNode,
  errors: ValidationError[],
  functionCatalog: ReadonlyMap<string, { displayName: string, parameters: FunctionParameter[], returnType: string }>,
  options: ValidateFunctionNodeOptions = {},
): void {
  if (options.requireFunctionName && !node.functionName) {
    errors.push({ nodeId: node.id, message: '函数节点缺少函数选择' })
    return
  }

  if (!node.functionName) {
    return
  }

  const func = functionCatalog.get(node.functionName)
  if (!func) {
    return
  }

  func.parameters.forEach((parameter) => {
    if (parameter.required) {
      const nodeParameter = node.parameters?.find((item) => item.name === parameter.name)
      if (!hasParameterValue(nodeParameter)) {
        errors.push({
          nodeId: node.id,
          message: `函数 ${func.displayName} 缺少必填参数: ${parameter.description}`,
        })
      }
    }
  })

  if (func.returnType === 'boolean') {
    return
  }

  if (!node.comparison) {
    errors.push({ nodeId: node.id, message: `函数 ${func.displayName} 缺少比较操作符` })
    return
  }

  if (requiresComparisonValue(node.comparison) && !hasComparableValue(node.value)) {
    errors.push({ nodeId: node.id, message: `函数 ${func.displayName} 缺少比较值` })
  }
}
