import type { TreeNode } from '../../types'
import { generateNodeId } from './id'

/**
 * 创建新的条件节点
 */
export function createConditionNode(parentId?: string, level: number = 0): TreeNode {
  return {
    id: generateNodeId(),
    type: 'condition',
    level,
    parentId,
    field: '',
    comparison: '==',
    value: '',
  }
}
