import type { NodeValue } from '../../types'
import type { ValidationError } from './types'
import { hasComparableValue, requiresComparisonValue } from './shared'

interface FieldConditionNode {
  id: string
  field?: string
  comparison?: string
  value?: NodeValue
}

export function validateFieldConditionNode(node: FieldConditionNode, errors: ValidationError[]): void {
  if (!node.field) {
    errors.push({ nodeId: node.id, message: '条件节点缺少字段选择' })
  }

  if (!node.comparison) {
    errors.push({ nodeId: node.id, message: '条件节点缺少比较操作符' })
    return
  }

  if (requiresComparisonValue(node.comparison) && !hasComparableValue(node.value)) {
    errors.push({ nodeId: node.id, message: '条件节点缺少比较值' })
  }
}
