import type { Token } from './types'

const KEYWORD_VALUES = new Set(['nil', 'null', 'true', 'false'])

export function classifyIdentifierToken(value: string): Token {
  if (KEYWORD_VALUES.has(value)) {
    return { type: 'KEYWORD', value }
  }

  if (value === 'lambda') {
    return { type: 'LAMBDA', value }
  }

  if (value === 'end') {
    return { type: 'END', value }
  }

  return { type: 'IDENTIFIER', value }
}
