import type { ASTNode, IdentifierNode } from '../ast.types'
import { createNilKeywordLiteral } from './literals'
import { type ParserRuntime, advance } from './runtime'

interface LambdaParsers {
  parseLogical: () => ASTNode
}

function parseLambdaBody(runtime: ParserRuntime, parsers: LambdaParsers): ASTNode {
  const expressions: ASTNode[] = []

  while (runtime.currentToken.type !== 'EOF' && runtime.currentToken.type !== 'END') {
    const expr = parsers.parseLogical()
    expressions.push(expr)

    if (runtime.currentToken.type === 'COMMA') {
      advance(runtime)
    } else {
      break
    }
  }

  if (expressions.length === 1) {
    return expressions[0]
  }

  if (expressions.length > 1) {
    const [first, ...rest] = expressions
    return rest.reduce<ASTNode>((acc, current) => ({
      type: 'LogicalExpression',
      operator: '&&',
      left: acc,
      right: current,
    }), first)
  }

  return createNilKeywordLiteral()
}

export function parseLambdaExpression(runtime: ParserRuntime, parsers: LambdaParsers): ASTNode {
  advance(runtime)

  if (runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === '(') {
    advance(runtime)
  }

  const parameters: IdentifierNode[] = []

  while (runtime.currentToken.type !== 'EOF' && !(runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === ')')) {
    if (parameters.length > 0) {
      if (runtime.currentToken.type === 'COMMA') {
        advance(runtime)
      } else {
        break
      }
    }

    if (runtime.currentToken.type === 'IDENTIFIER') {
      parameters.push({ type: 'Identifier', name: String(runtime.currentToken.value) })
      advance(runtime)
    } else {
      break
    }
  }

  if (runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === ')') {
    advance(runtime)
  }

  if (runtime.currentToken.type === 'ARROW') {
    advance(runtime)
  }

  const body = parseLambdaBody(runtime, parsers)

  if (runtime.currentToken.type === 'END') {
    advance(runtime)
  }

  return {
    type: 'LambdaExpression',
    parameters,
    body,
  }
}
