import type { Token } from '../tokenizer/index'
import type { ASTNode, ParseResult } from '../ast.types'
import { createParserRuntime } from './runtime'
import {
  parseComparisonExpression,
  parseLogicalExpression,
  parseUnaryExpression,
} from './operators'
import { parsePrimaryExpression } from './primary'
import { parseLambdaExpression } from './lambda'

export type { ASTNode, ParseResult } from '../ast.types'

export function parseTokensToAST(tokens: Token[]): ParseResult {
  const runtime = createParserRuntime(tokens)

  function parseLogical(): ASTNode {
    return parseLogicalExpression(runtime, parseComparison)
  }

  function parseComparison(): ASTNode {
    return parseComparisonExpression(runtime, parseUnary)
  }

  function parseUnary(): ASTNode {
    return parseUnaryExpression(runtime, parsePrimary)
  }

  function parsePrimary(): ASTNode {
    return parsePrimaryExpression(runtime, { parseLogical, parseLambda })
  }

  function parseLambda(): ASTNode {
    return parseLambdaExpression(runtime, { parseLogical })
  }

  const ast = parseLogical()

  return {
    ast,
    position: runtime.position,
  }
}
