import { type TokenizerRuntime, advance, peek } from './runtime'
import type { Token } from './types'

function consumePairToken(runtime: TokenizerRuntime, tokens: Token[], pair: string): boolean {
  if (`${runtime.current}${peek(runtime)}` !== pair) {
    return false
  }

  if (pair === '&&' || pair === '||') {
    tokens.push({ type: 'LOGICAL', value: pair })
  } else if (pair === '!=' || pair === '==' || pair === '>=' || pair === '<=') {
    tokens.push({ type: 'COMPARISON', value: pair })
  } else if (pair === '->') {
    tokens.push({ type: 'ARROW', value: pair })
  } else {
    return false
  }

  advance(runtime)
  advance(runtime)
  return true
}

export function consumeCompositeOperators(runtime: TokenizerRuntime, tokens: Token[]): boolean {
  const pairs = ['&&', '||', '!=', '==', '>=', '<=', '->']
  for (const pair of pairs) {
    if (consumePairToken(runtime, tokens, pair)) {
      return true
    }
  }

  const next = peek(runtime)
  if (runtime.current === '!' && next !== '=' && next !== '~') {
    tokens.push({ type: 'UNARY', value: runtime.current })
    advance(runtime)
    return true
  }

  return false
}

export function consumeSingleOperators(runtime: TokenizerRuntime, tokens: Token[]): boolean {
  if (runtime.current === '>' || runtime.current === '<') {
    tokens.push({ type: 'COMPARISON', value: runtime.current })
    advance(runtime)
    return true
  }

  if (runtime.current === '-') {
    tokens.push({ type: 'OPERATOR', value: runtime.current })
    advance(runtime)
    return true
  }

  return false
}
