import { AVIATOR_FUNCTIONS } from '../../constants'

const RETURN_TYPE_BY_FUNCTION = new Map(AVIATOR_FUNCTIONS.map((fn) => [fn.name, fn.returnType]))

export function isBooleanReturnFunction(functionName?: string): boolean {
  if (!functionName) {
    return false
  }
  return RETURN_TYPE_BY_FUNCTION.get(functionName) === 'boolean'
}
