import type { FieldOption } from '../../types'
import { getExampleValue, getFieldType, isComplexObject } from './classify'
import { sortFieldOptions } from './sort'

export function extractFieldPaths(
  obj: unknown,
  prefix = '',
  maxDepth = 8,
  currentDepth = 0,
): FieldOption[] {
  if (currentDepth >= maxDepth || obj === null || obj === undefined) {
    return []
  }

  const fields: FieldOption[] = []

  if (Array.isArray(obj)) {
    if (obj.length > 0) {
      return extractFieldPaths(obj[0], prefix, maxDepth, currentDepth + 1)
    }
    return fields
  }

  if (typeof obj === 'object') {
    const source = obj as Record<string, unknown>
    Object.keys(source).forEach((key) => {
      const fieldPath = prefix ? `${prefix}.${key}` : key
      const value = source[key]

      if (!isComplexObject(value)) {
        fields.push({
          label: fieldPath,
          value: fieldPath,
          type: getFieldType(value),
          example: getExampleValue(value),
        })
      }

      if (value && typeof value === 'object') {
        const subFields = extractFieldPaths(value, fieldPath, maxDepth, currentDepth + 1)
        fields.push(...subFields)
      }
    })
  }

  return fields
}

export function extractFieldsFromJson(jsonString: string): FieldOption[] {
  if (!jsonString || jsonString.trim() === '' || jsonString.trim() === '{}') {
    return []
  }

  try {
    const jsonData = JSON.parse(jsonString)
    const fields = extractFieldPaths(jsonData)
    const validFields = fields.filter((field) => field.type !== 'object' && field.type !== 'null')
    return sortFieldOptions(validFields)
  } catch {
    return []
  }
}
