import type { ASTNode, IdentifierNode, MemberExpressionNode } from '../../ast.types'
import { type ParserRuntime, advance } from '../runtime'
import type { PrimaryParsers } from './types'

function parseCallArguments(runtime: ParserRuntime, parsers: PrimaryParsers): ASTNode[] {
  const args: ASTNode[] = []

  while (runtime.currentToken.type !== 'EOF' && !(runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === ')')) {
    if (args.length > 0) {
      if (runtime.currentToken.type === 'COMMA') {
        advance(runtime)
      } else {
        break
      }
    }

    const arg = parsers.parseLogical()
    args.push(arg)
  }

  if (runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === ')') {
    advance(runtime)
  }

  return args
}

function parseMemberExpression(runtime: ParserRuntime, parsers: PrimaryParsers, name: string): IdentifierNode | MemberExpressionNode {
  let node: IdentifierNode | MemberExpressionNode = { type: 'Identifier', name }

  while (runtime.currentToken.type === 'BRACKET' && runtime.currentToken.value === '[') {
    advance(runtime)
    const property = parsers.parseLogical()
    if (runtime.currentToken.type === 'BRACKET' && runtime.currentToken.value === ']') {
      advance(runtime)
    }

    node = {
      type: 'MemberExpression',
      object: node,
      property,
      computed: true,
    }
  }

  return node
}

export function parseIdentifierExpression(runtime: ParserRuntime, parsers: PrimaryParsers): ASTNode {
  const name = String(runtime.currentToken.value)
  advance(runtime)

  if (runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === '(') {
    advance(runtime)
    return {
      type: 'CallExpression',
      callee: { type: 'Identifier', name },
      arguments: parseCallArguments(runtime, parsers),
    }
  }

  return parseMemberExpression(runtime, parsers, name)
}
