import type { FunctionModeParameterRuleContext } from './types'
import { assignSimpleParameterValue } from './shared'

export function applyLiteralRule(context: FunctionModeParameterRuleContext): boolean {
  const { arg, index, parameters } = context
  if (arg.type !== 'Literal') return false

  assignSimpleParameterValue(parameters[index], arg.value, 'value')
  return true
}
