import type { ValidationError, ValidationNode } from './types'

interface GroupValidationNode {
  id: string
  expanded?: boolean
  children?: ValidationNode[]
}

export function validateGroupNode(
  node: GroupValidationNode,
  errors: ValidationError[],
  validateChild: (child: ValidationNode) => void,
): void {
  if (node.expanded && (!node.children || node.children.length === 0)) {
    errors.push({ nodeId: node.id, message: '分组节点为空，请添加子条件' })
    return
  }

  node.children?.forEach(validateChild)
}
