import type { TreeNode } from '../types'
import type { GeneratorContext } from './nodeExpressionGenerator.types'
import { resolveInlineFieldModeOperatorExpression, resolveTerminalFieldModeOperatorExpression } from './field-mode-operators'
import { formatFieldComparisonValue } from './field-mode-value'

export function generateFieldModeConditionExpression(node: TreeNode, context: GeneratorContext): string {
  if (!node.field || !node.comparison) return ''

  if (node.value === undefined || node.value === null) {
    const expr = `${node.field} ${node.comparison}`
    if (node.isNegated) {
      return `!(${expr})`
    }
    return expr
  }

  const value = formatFieldComparisonValue(node, context)
  const terminalOperatorExpression = resolveTerminalFieldModeOperatorExpression({
    node,
    context,
    formattedValue: value,
  })
  if (terminalOperatorExpression) {
    return terminalOperatorExpression
  }

  const inlineOperatorExpression = resolveInlineFieldModeOperatorExpression(node.comparison, node.field, value)
  const conditionExpr = inlineOperatorExpression ?? `${node.field} ${node.comparison} ${value}`

  if (node.isNegated) {
    return `!(${conditionExpr})`
  }

  return conditionExpr
}
