import type { ASTNode } from '../ast.types'
import { toLogicalOperator } from './literals'
import { type ParserRuntime, advance } from './runtime'

export function parseLogicalExpression(
  runtime: ParserRuntime,
  parseComparison: () => ASTNode,
): ASTNode {
  let left = parseComparison()

  while (runtime.currentToken.type === 'LOGICAL') {
    const operator = toLogicalOperator(String(runtime.currentToken.value))
    advance(runtime)
    const right = parseComparison()
    left = { type: 'LogicalExpression', operator, left, right }
  }

  return left
}

export function parseComparisonExpression(
  runtime: ParserRuntime,
  parseUnary: () => ASTNode,
): ASTNode {
  let left = parseUnary()

  while (runtime.currentToken.type === 'COMPARISON') {
    const operator = String(runtime.currentToken.value)
    advance(runtime)
    const right = parseUnary()
    left = { type: 'BinaryExpression', operator, left, right }
  }

  return left
}

export function parseUnaryExpression(runtime: ParserRuntime, parsePrimary: () => ASTNode): ASTNode {
  if (runtime.currentToken.type === 'UNARY' && runtime.currentToken.value === '!') {
    advance(runtime)
    const argument = parseUnaryExpression(runtime, parsePrimary)
    return { type: 'UnaryExpression', operator: '!', argument, prefix: true }
  }

  return parsePrimary()
}
