import type { AviatorExpressionEngineContext } from '../../../domain/contracts'
import type { AviatorTreeNode } from '../../../domain/models'
import { LegacyAviatorExpressionEngine } from '../../../infrastructure/legacy/LegacyAviatorExpressionEngine'
import {
  type ParseExpressionResult,
  parseExpression,
} from '../../../infrastructure/engine/parser'
import { createFieldTypeResolver } from './fieldResolver'
import { createAvailableFieldsStore, createParameterDataTypesStore } from './stores'
import type {
  AviatorExpressionService,
  CreateAviatorExpressionServiceOptions,
} from './types'

export type {
  AviatorExpressionService,
  CreateAviatorExpressionServiceOptions,
} from './types'

function isEmptyExpression(expression: string): boolean {
  return !expression || !expression.trim()
}

export function createAviatorExpressionService(
  options: CreateAviatorExpressionServiceOptions,
): AviatorExpressionService {
  const engine = options.engine || new LegacyAviatorExpressionEngine()
  const fieldsStore = createAvailableFieldsStore(options.availableFields || [])
  const dataTypesStore = createParameterDataTypesStore()
  const resolveFieldType = createFieldTypeResolver(fieldsStore.getAvailableFields, options.getFieldTypeForNode)

  const createContext = (): AviatorExpressionEngineContext => ({
    availableFields: fieldsStore.getAvailableFields(),
    parameterDataTypes: dataTypesStore.parameterDataTypes,
    getFieldTypeForNode: resolveFieldType,
  })

  const parseDetailed = (expression: string): ParseExpressionResult => {
    if (isEmptyExpression(expression)) {
      return { success: true, nodes: [] }
    }

    return parseExpression(expression, createContext())
  }

  const parse = (expression: string): AviatorTreeNode[] => {
    return parseDetailed(expression).nodes
  }

  const generate = (nodes: AviatorTreeNode[]): string => {
    return engine.generate(nodes, createContext())
  }

  const validate = (nodes: AviatorTreeNode[]) => {
    return engine.validate(nodes)
  }

  return {
    parseDetailed,
    parse,
    generate,
    validate,
    getAvailableFields: fieldsStore.getAvailableFields,
    setAvailableFields: fieldsStore.setAvailableFields,
    getParameterDataTypes: dataTypesStore.getParameterDataTypes,
    setParameterDataType: dataTypesStore.setParameterDataType,
    clearParameterDataTypes: dataTypesStore.clearParameterDataTypes,
  }
}
