import { type TokenizerRuntime, advance } from './runtime'

export function readString(runtime: TokenizerRuntime, quote: string): string {
  let value = ''
  advance(runtime)
  while (runtime.current && runtime.current !== quote) {
    value += runtime.current
    advance(runtime)
  }
  if (runtime.current === quote) {
    advance(runtime)
  }
  return value
}

export function readNumber(runtime: TokenizerRuntime): string {
  let value = ''
  while (runtime.current && /[0-9.]/.test(runtime.current)) {
    value += runtime.current
    advance(runtime)
  }
  return value
}

export function readIdentifier(runtime: TokenizerRuntime): string {
  let value = ''
  while (runtime.current && /[\w.]/.test(runtime.current)) {
    value += runtime.current
    advance(runtime)
  }
  return value
}
