export function resolveInlineFieldModeOperatorExpression(
  comparison: string,
  field: string,
  formattedValue: unknown,
): string | null {
  if (comparison === 'contains') {
    return `string.contains(${field}, ${formattedValue})`
  }

  if (comparison === 'startsWith') {
    return `string.startsWith(${field}, ${formattedValue})`
  }

  if (comparison === 'endsWith') {
    return `string.endsWith(${field}, ${formattedValue})`
  }

  return null
}
