import type { ASTNode } from '../../ast.types'
import { type ParserRuntime, advance } from '../runtime'
import type { PrimaryParsers } from './types'

export function parseGroupExpression(runtime: ParserRuntime, parsers: PrimaryParsers): ASTNode {
  advance(runtime)
  const expression = parsers.parseLogical()
  if (runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === ')') {
    advance(runtime)
  }
  return { type: 'GroupExpression', expression }
}
