import type { AviatorFieldOption } from '../../../domain/models'

export interface AvailableFieldsStore {
  getAvailableFields: () => AviatorFieldOption[]
  setAvailableFields: (fields: AviatorFieldOption[]) => void
}

export function createAvailableFieldsStore(initialFields: AviatorFieldOption[]): AvailableFieldsStore {
  let availableFields = [...(initialFields || [])]

  return {
    getAvailableFields: () => availableFields,
    setAvailableFields: (fields: AviatorFieldOption[]) => {
      availableFields = [...(fields || [])]
    },
  }
}

export interface ParameterDataTypesStore {
  parameterDataTypes: Map<string, Map<string, string>>
  getParameterDataTypes: () => Map<string, Map<string, string>>
  setParameterDataType: (nodeId: string, parameterName: string, dataType: string) => void
  clearParameterDataTypes: () => void
}

export function createParameterDataTypesStore(): ParameterDataTypesStore {
  const parameterDataTypes = new Map<string, Map<string, string>>()

  return {
    parameterDataTypes,
    getParameterDataTypes: () => parameterDataTypes,
    setParameterDataType: (nodeId: string, parameterName: string, dataType: string) => {
      const nodeDataTypes = parameterDataTypes.get(nodeId) || new Map<string, string>()
      nodeDataTypes.set(parameterName, dataType)
      parameterDataTypes.set(nodeId, nodeDataTypes)
    },
    clearParameterDataTypes: () => {
      parameterDataTypes.clear()
    },
  }
}
