import type { ASTNode } from '../../ast.types'
import { toKeywordLiteral } from '../literals'
import { type ParserRuntime, advance } from '../runtime'

export function parseLiteralExpression(runtime: ParserRuntime): ASTNode | null {
  if (runtime.currentToken.type === 'STRING') {
    const value = String(runtime.currentToken.value)
    advance(runtime)
    return { type: 'Literal', value, dataType: 'string' }
  }

  if (runtime.currentToken.type === 'KEYWORD') {
    const value = toKeywordLiteral(String(runtime.currentToken.value))
    advance(runtime)
    return { type: 'Literal', value, dataType: 'keyword' }
  }

  if (runtime.currentToken.type === 'NUMBER') {
    const value = Number(runtime.currentToken.value)
    advance(runtime)
    return { type: 'Literal', value, dataType: 'number' }
  }

  return null
}
