import type { ASTNode } from '../ast.types'
import {
  type PrimaryParsers,
  parseGroupExpression,
  parseIdentifierExpression,
  parseLiteralExpression,
} from './primary-handlers'
import type { ParserRuntime } from './runtime'

export function parsePrimaryExpression(runtime: ParserRuntime, parsers: PrimaryParsers): ASTNode {
  if (runtime.currentToken.type === 'LAMBDA') {
    return parsers.parseLambda()
  }

  if (runtime.currentToken.type === 'PAREN' && runtime.currentToken.value === '(') {
    return parseGroupExpression(runtime, parsers)
  }

  if (runtime.currentToken.type === 'IDENTIFIER') {
    return parseIdentifierExpression(runtime, parsers)
  }

  const literalNode = parseLiteralExpression(runtime)
  if (literalNode) {
    return literalNode
  }

  throw new Error(`Unexpected token: ${runtime.currentToken.type} (${runtime.currentToken.value})`)
}
