import { type TokenizerRuntime, advance } from './runtime'
import type { Token } from './types'

export function consumeDelimiter(runtime: TokenizerRuntime, tokens: Token[]): boolean {
  if (runtime.current === '(' || runtime.current === ')') {
    tokens.push({ type: 'PAREN', value: runtime.current })
    advance(runtime)
    return true
  }

  if (runtime.current === '[' || runtime.current === ']') {
    tokens.push({ type: 'BRACKET', value: runtime.current })
    advance(runtime)
    return true
  }

  if (runtime.current === ',') {
    tokens.push({ type: 'COMMA', value: runtime.current })
    advance(runtime)
    return true
  }

  return false
}
