import { type TokenizerRuntime, advance } from './runtime'
import type { Token } from './types'
import { consumeDelimiter } from './scanners.delimiters'
import { consumeLiteralOrIdentifier } from './scanners.literal'
import { consumeCompositeOperators, consumeSingleOperators } from './scanners.operators'

export function consumeNextToken(runtime: TokenizerRuntime, tokens: Token[]): void {
  if (consumeLiteralOrIdentifier(runtime, tokens)) {
    return
  }

  if (consumeCompositeOperators(runtime, tokens)) {
    return
  }

  if (consumeDelimiter(runtime, tokens)) {
    return
  }

  if (consumeSingleOperators(runtime, tokens)) {
    return
  }

  advance(runtime)
}
