import type { BinaryExpressionNode } from './ast.types'
import type { AstNodeRuleDefinition } from './astToTreeNode.convert.rule-registry'
import { isNilLiteral } from './astToTreeNode.convert.helpers'

function isBelongSeqSomeCall(node: BinaryExpressionNode): boolean {
  if (node.left.type !== 'CallExpression' || node.left.callee.name !== 'seq.some') {
    return false
  }

  if (node.left.arguments.length !== 2) {
    return false
  }

  const secondArg = node.left.arguments[1]
  if (secondArg.type !== 'LambdaExpression') {
    return false
  }

  const lambdaBody = secondArg.body
  if (!(lambdaBody.type === 'CallExpression'
    && lambdaBody.callee.name === 'include'
    && lambdaBody.arguments.length === 2)) {
    return false
  }

  const includeFirstArg = lambdaBody.arguments[0]
  return includeFirstArg.type === 'CallExpression' && includeFirstArg.callee.name === 'seq.list'
}

function tryHandleBelongNilComparison(
  options: Parameters<AstNodeRuleDefinition<BinaryExpressionNode>['handler']>[0],
) {
  const { node, level, parentId, convert } = options
  if (!isBelongSeqSomeCall(node)) {
    return null
  }

  const conditionNode = convert(node.left, level, parentId)
  if (isNilLiteral(node.right) && node.operator === '==') {
    conditionNode.isNegated = true
  }

  return conditionNode
}

export const binaryBelongNilRule: AstNodeRuleDefinition<BinaryExpressionNode> = {
  name: 'belong-nil-comparison',
  priority: 100,
  handler: tryHandleBelongNilComparison,
}
